import * as fs from 'fs';
import * as os from 'os';
import * as path from 'path';
import { rimraf } from 'rimraf';
import { Dirty } from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty backpressure handling', () => {
  it('should stop flushing remaining queue items when write stream signals backpressure', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'test.db');
    const db = new Dirty(dbPath);

    db.on('load', () => {
      const writeStream = (db as any)._writeStream;
      let writeCallCount = 0;
      const originalWrite = writeStream.write.bind(writeStream);
      let queueSizeAfterFirstWrite = -1;

      writeStream.write = function(data: string, cb: Function) {
        writeCallCount++;
        if (writeCallCount === 1) {
          // Simulate backpressure on first write
          originalWrite(data, cb);
          queueSizeAfterFirstWrite = (db as any)._queue.size;
          (db as any)._waitForDrain = true;
          return false;
        }
        return originalWrite(data, cb);
      };

      // Queue multiple keys at once
      db.set('alpha', 1);
      db.set('beta', 2);
      db.set('gamma', 3);

      setImmediate(() => {
        // Original: loop breaks after first write due to backpressure
        // So 'beta' and 'gamma' remain in queue → queueSizeAfterFirstWrite >= 2
        // Mutated: loop continues, all items written → queueSizeAfterFirstWrite = 0
        expect(queueSizeAfterFirstWrite).toBeGreaterThanOrEqual(2);

        db.close();
        db.on('write_close', () => {
          rimraf(tmpDir).then(() => done()).catch(done);
        });
      });
    });

    db.on('error', done);
  });
});
